import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"那不勒斯护卫术","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/运动类/那不勒斯护卫术.md","filePath":"4.资源分区/6.技艺及称号/运动类/那不勒斯护卫术.md"}'),d={name:"4.资源分区/6.技艺及称号/运动类/那不勒斯护卫术.md"};function _(p,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"那不勒斯护卫术",tabindex:"-1"},[s("那不勒斯护卫术 "),e("a",{class:"header-anchor",href:"#那不勒斯护卫术","aria-label":'Permalink to "那不勒斯护卫术"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001F")])])],-1),o('<h1 id="那不勒斯护卫术-1" tabindex="-1">那不勒斯护卫术 <a class="header-anchor" href="#那不勒斯护卫术-1" aria-label="Permalink to &quot;那不勒斯护卫术&quot;">​</a></h1><p>那不勒斯护卫术<br> A+4000<br> 作为那不勒斯的王族护卫官，威卡毕博的铁球技术不同于齐贝林家族的用于医术和处刑的铁球技术，而是更注重于保护皇族和杀伤敌人的技术，并且会使用一种造型独特的「爆裂铁球」来施展。</p><p>爆裂铁球<br> 50/个<br> 这是一颗棕红色的，上面嵌有十二颗被称为「卫星」的小铁珠的铁球。爆裂铁球在投掷后便不再拥有它原本的效果，除非将「卫星」重新安放回铁球上，但驱动爆裂铁球的并非「黄金回转」，所以即使没有学习过铁球回转，也可以在投掷爆裂铁球后如同拥有【回力】一样，正常唤回爆裂铁球。</p><p>在掌握那不勒斯护卫术后，投掷爆裂铁球时，爆裂铁球会在击中敌人或受到物体阻碍时自然炸裂，产生冲击波并爆发出「卫星」，以落点为中心15米半径范围内的所有敌人都需要进行一次反射检定以对抗那次伤害出目，若对抗失败，则不可避免的进入「左半身失调」状态，这是一个A级环境来源的肢体妨碍效果，持续一轮。所谓的「左半身失调」是指在被铁球/冲击波/卫星击中后，会暂时的失去对于左半身和整个左边的感知的状态，陷入「左半身失调」的敌人的视距丧失一半（并非范围，而是广度），敏感范围随之丧失一半，并会使他们的运动、反射、攻击检定减少一半，失去所有的洞察防御。</p><p>同时，每轮一次，在受到一次攻击时，若使用者手中还持有者铁球，那么便可以使用一个反射动作让铁球在手中高速转动，反向扭动并硬化肌肉增加防御，针对本次攻击获得等同于运动技能等级的伤害出目抵消，这视为进行了一次招架。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
